const B64="";const bytes=Uint8Array.from(atob(B64),c=>c.charCodeAt(0));const CORS={"access-control-allow-origin":"*","access-control-allow-methods":"GET,POST,OPTIONS","access-control-allow-headers":"content-type"};export default{async fetch(req,env){const url=new URL(req.url);const p=url.pathname;if(req.method==="OPTIONS")return new Response(null,{headers:CORS});if(p==="/notes"){const l=await env.NOTES.list();const out={};for(const k of l.keys){const v=await env.NOTES.get(k.name);if(v){try{out[k.name]=JSON.parse(v);}catch(e){}}}return new Response(JSON.stringify(out),{headers:{"content-type":"application/json",...CORS}});}if(p==="/note"){if(req.method==="POST"){let b={};try{b=await req.json();}catch(e){}const dot=String(b.dot||"");if(!dot)return new Response(JSON.stringify({err:"no dot"}),{status:400,headers:{"content-type":"application/json",...CORS}});const note=b.note||"",st=b.status||"",rn=b.rn||"";if(!note&&!st&&!rn){await env.NOTES.delete(dot);}else{await env.NOTES.put(dot,JSON.stringify({note:note,status:st,rn:rn,ts:Date.now()}));}return new Response(JSON.stringify({ok:true}),{headers:{"content-type":"application/json",...CORS}});}const dot=url.searchParams.get("dot")||"";const v=await env.NOTES.get(dot);return new Response(v||"{}",{headers:{"content-type":"application/json",...CORS}});}return new Response(bytes,{headers:{"content-type":"text/html;charset=utf-8","cache-control":"no-store"}});}};
